// Normalize and validate form fields
const input = $input.first().json;

// Generate idempotent request_id from email + date + timestamp
const crypto = require('crypto');
const hash = crypto.createHash('sha256')
  .update(`${input.requester_email}-${input.requested_date}-${Date.now()}`)
  .digest('hex')
  .substring(0, 16);

return [{
  json: {
    request_id: `form-${hash}`,
    requester_name: (input.requester_name || '').trim(),
    requester_email: (input.requester_email || '').trim().toLowerCase(),
    requester_organization: (input.requester_organization || '').trim() || null,
    event_name: (input.event_name || '').trim(),
    event_description: (input.event_description || '').trim() || null,
    requested_date: input.requested_date,
    requested_start_time: input.requested_start_time,
    requested_end_time: input.requested_end_time,
    room_requested: (input.room_requested || '').trim() || null,
    estimated_attendees: parseInt(input.estimated_attendees) || null,
    setup_requirements_raw: (input.setup_requirements || '').trim() || null
  }
}];

// Determine calendar availability based on returned events
const events = $input.all();
const formData = $('Validate & Transform').first().json;

// If no events found, the time slot is available
const calendar_available = events.length === 0 || (events.length === 1 && !events[0].json.id);

return [{
  json: {
    ...formData,
    calendar_available: calendar_available
  }
}];

// Generate calendar conflict response
const formData = $('Validate & Transform').first().json;

return [{
  json: {
    ...formData,
    decision: 'calendar_conflict',
    is_eligible: null,
    eligibility_reason: null,
    pricing_tier: null,
    estimated_cost: null,
    room_assignment: formData.room_requested,
    setup_config: null,
    draft_response: `Dear ${formData.requester_name},\n\nThank you for your interest in reserving event space at the Center for Government & Civic Service.\n\nUnfortunately, the ${formData.room_requested || 'requested room'} is not available on ${formData.requested_date} from ${formData.requested_start_time} to ${formData.requested_end_time}. The time slot you selected conflicts with an existing reservation.\n\nWe would be happy to help you find an alternative date or time. Please visit our calendar to view current availability, or reply to this email with your preferred alternatives.\n\nBest regards,\nCGCS Event Space Team\nAustin Community College`,
    errors: []
  }
}];

// Merge agent response with form data for DB insert
const agentResult = $input.first().json;
const formData = $('Validate & Transform').first().json;

return [{
  json: {
    request_id: formData.request_id,
    requester_name: formData.requester_name,
    requester_email: formData.requester_email,
    requester_organization: formData.requester_organization,
    event_name: formData.event_name,
    decision: agentResult.decision,
    is_eligible: agentResult.is_eligible,
    eligibility_reason: agentResult.eligibility_reason,
    pricing_tier: agentResult.pricing_tier,
    estimated_cost: agentResult.estimated_cost,
    room_assignment: agentResult.room_assignment,
    draft_response: agentResult.draft_response,
    calendar_available: formData.calendar_available
  }
}];
